import { execution } from '@dynatrace-sdk/automation-utils';

export default async function ({ execution_id }) {
  const ex = await execution(execution_id);

  // Manual: ex.params.event.params | Davis trigger: ex.event
  const src = ex.params?.event?.params || ex.event || {};
  console.log('source data:', JSON.stringify(src));

  const severity   = src['problem.severityLevel'] || 'OTHER';
  const problemId  = src['problem.id']             || 'P-MANUAL-TEST';
  const title      = src['problem.title']          || 'Manual Test';
  const detTime    = src['problem.detectionTime']  || new Date().toISOString();
  const url        = src['problem.url']            || '';

  let impact = '4';
  let urgency = '4';
  if (severity === 'AVAILABILITY') { impact = '1'; urgency = '1'; }
  else if (severity === 'INFRASTRUCTURE') { impact = '2'; urgency = '2'; }
  else if (severity === 'PERFORMANCE') { impact = '2'; urgency = '2'; }
  else if (severity === 'RESOURCE') { impact = '3'; urgency = '3'; }
  else if (severity === 'CUSTOM_ALERT') { impact = '4'; urgency = '4'; }

  const impactLabel = `${impact} - ${impact === '1' ? 'High' : impact === '2' ? 'Medium' : impact === '3' ? 'Low' : 'Low'}`;
  const urgencyLabel = `${urgency} - ${urgency === '1' ? 'High' : urgency === '2' ? 'Medium' : urgency === '3' ? 'Low' : 'Low'}`;
  const priorityLabel = `${impact} - ${impact === '1' ? 'High' : impact === '2' ? 'Medium' : impact === '3' ? 'Low' : 'Low'}`;

  return {
    impact,
    urgency,
    impactLabel,
    urgencyLabel,
    priorityLabel,
    routingPriority: impact,
    problemId,
    title,
    severity,
    detTime,
    url
  };
}
